BEGIN;

CREATE TABLE IF NOT EXISTS public.pg254_blink_static_legacy_runtime_promotions_20260629_backup AS
SELECT now() AS backed_up_at, r.*
FROM public.card_battle_rules r
WHERE false;

INSERT INTO public.pg254_blink_static_legacy_runtime_promotions_20260629_backup
SELECT now() AS backed_up_at, r.*
FROM public.card_battle_rules r
WHERE r.normalized_name IN (SELECT normalized_name FROM (VALUES ('reckless barbarian'), ('sacrifice'), ('geosurge'), ('mardu devotee'), ('orcish lumberjack'), ('faeburrow elder'), ('neoform'), ('ephemerate'), ('displacer kitten'), ('emiel the blessed'), ('deafening silence'), ('archon of emeria'), ('eidolon of rhetoric'), ('ethersworn canonist')) AS v(normalized_name))
AND NOT EXISTS (
  SELECT 1 FROM public.pg254_blink_static_legacy_runtime_promotions_20260629_backup b
  WHERE b.normalized_name = r.normalized_name
    AND b.logical_rule_key = r.logical_rule_key
);

DO $$
DECLARE v_missing text;
BEGIN
  WITH proposed(normalized_name, card_name, oracle_hash) AS (VALUES ('reckless barbarian', 'Reckless Barbarian', '2624a42fe38948a6225a247ba102d11d'), ('sacrifice', 'Sacrifice', '57ca43a79d7a466b97c5be6afddbbe37'), ('geosurge', 'Geosurge', 'a19284fe4a3b41b3e37b14f037c91621'), ('mardu devotee', 'Mardu Devotee', '95569a7b24c32433f2f8386c32688a50'), ('orcish lumberjack', 'Orcish Lumberjack', 'b63a428ffc3dff109028c603c0f54923'), ('faeburrow elder', 'Faeburrow Elder', '85c90e2fe09a1b85984007a14e3db900'), ('neoform', 'Neoform', 'ae81715abd94b17c07451a09cf5b8db6'), ('ephemerate', 'Ephemerate', '4671452857f7b532c0c9cc6088b3e25c'), ('displacer kitten', 'Displacer Kitten', '16da6e6f7355a5732ee2f80d55f35ebc'), ('emiel the blessed', 'Emiel the Blessed', '9c568dbb78c72979a6e2e528f2ea5385'), ('deafening silence', 'Deafening Silence', '7ee68f02b4a79a4c3e00fbe14caceda1'), ('archon of emeria', 'Archon of Emeria', 'a52d85813ecf212a3bfc84e249a2c90a'), ('eidolon of rhetoric', 'Eidolon of Rhetoric', 'cf8c850002241fd1afe4e8ca46884774'), ('ethersworn canonist', 'Ethersworn Canonist', 'e8466942a00d320a7a9c067c0861fb27'))
  SELECT string_agg(p.card_name, ', ' ORDER BY p.card_name) INTO v_missing
  FROM proposed p
  WHERE NOT EXISTS (
    SELECT 1 FROM public.cards c
    WHERE (lower(c.name) = p.normalized_name OR split_part(lower(c.name), ' // ', 1) = p.normalized_name)
      AND md5(coalesce(c.oracle_text, '')) = p.oracle_hash
  );
  IF v_missing IS NOT NULL THEN
    RAISE EXCEPTION 'PG254 abort: expected at least one Oracle-hash-matched cards row for every proposed card: %', v_missing;
  END IF;
END $$;

WITH proposed(normalized_name, card_name, oracle_hash, logical_rule_key, effect_json, deck_role_json, source, confidence, review_status, execution_status, notes, shadow_handling) AS (
  VALUES
    ('reckless barbarian', 'Reckless Barbarian', '2624a42fe38948a6225a247ba102d11d', 'battle_rule_v1:3e4644b909f23750472f43f57c3992c9', '{"battle_model_scope":"creature_sacrifice_add_two_red_mana_v1","effect":"creature","is_mana_source":true,"mana_produced":2,"produces":"R"}'::jsonb, '{"category":"ramp","effect":"creature","subtype":"mana_dork"}'::jsonb, 'curated', 0.96, 'verified', 'auto', 'PG254: promoted focused runtime rule for Reckless Barbarian; source is local XMage-backed ManaLoom runtime/test batch for blink, static restriction, or legacy exact waiver.', 'deprecate_nonmatching_rows'),
    ('sacrifice', 'Sacrifice', '57ca43a79d7a466b97c5be6afddbbe37', 'battle_rule_v1:9f494d943f370fc23f70ab219b82c70b', '{"battle_model_scope":"sacrifice_creature_add_black_equal_sacrificed_mana_value_v1","effect":"ramp_ritual","instant":true,"mana_produced_from_sacrificed_cmc":true,"produces":"B","requires_sacrifice_creature":true}'::jsonb, '{"category":"ramp","effect":"ramp_ritual","timing":"instant"}'::jsonb, 'curated', 0.96, 'verified', 'auto', 'PG254: promoted focused runtime rule for Sacrifice; source is local XMage-backed ManaLoom runtime/test batch for blink, static restriction, or legacy exact waiver.', 'deprecate_nonmatching_rows'),
    ('geosurge', 'Geosurge', 'a19284fe4a3b41b3e37b14f037c91621', 'battle_rule_v1:2323eaddfebeeae63ff261b27cd676f8', '{"battle_model_scope":"add_seven_red_spend_only_artifact_or_creature_spells_v1","effect":"ramp_ritual","mana_produced":7,"produces":"R","restricted_to_spell_categories":["artifact_spell","creature_spell"]}'::jsonb, '{"category":"ramp","effect":"ramp_ritual"}'::jsonb, 'curated', 0.96, 'verified', 'auto', 'PG254: promoted focused runtime rule for Geosurge; source is local XMage-backed ManaLoom runtime/test batch for blink, static restriction, or legacy exact waiver.', 'deprecate_nonmatching_rows'),
    ('mardu devotee', 'Mardu Devotee', '95569a7b24c32433f2f8386c32688a50', 'battle_rule_v1:163c8c72b0d88900703479b29584941d', '{"activation_cost_generic":1,"battle_model_scope":"creature_etb_scry_two_and_one_mana_mardu_filter_v1","effect":"creature","etb_scry_count":2,"mana_filter_once_per_turn":true,"power":1,"produces":"RWB","toughness":2}'::jsonb, '{"category":"unknown","effect":"creature"}'::jsonb, 'curated', 0.96, 'verified', 'auto', 'PG254: promoted focused runtime rule for Mardu Devotee; source is local XMage-backed ManaLoom runtime/test batch for blink, static restriction, or legacy exact waiver.', 'deprecate_nonmatching_rows'),
    ('orcish lumberjack', 'Orcish Lumberjack', 'b63a428ffc3dff109028c603c0f54923', 'battle_rule_v1:3928f623fa6bea3e5c2fac2983d8df26', '{"battle_model_scope":"creature_tap_sacrifice_forest_add_three_red_or_green_v1","effect":"creature","is_mana_source":true,"mana_produced":3,"power":1,"produces":"RG","requires_sacrifice_forest_for_mana":true,"toughness":1}'::jsonb, '{"category":"ramp","effect":"creature","subtype":"mana_dork"}'::jsonb, 'curated', 0.96, 'verified', 'auto', 'PG254: promoted focused runtime rule for Orcish Lumberjack; source is local XMage-backed ManaLoom runtime/test batch for blink, static restriction, or legacy exact waiver.', 'deprecate_nonmatching_rows'),
    ('faeburrow elder', 'Faeburrow Elder', '85c90e2fe09a1b85984007a14e3db900', 'battle_rule_v1:ba732f55ab31865df49e463277d20469', '{"battle_model_scope":"creature_tap_add_one_mana_each_color_among_permanents_v1","effect":"creature","is_mana_source":true,"mana_produced_from_colors_among_permanents":true,"produces":"WUBRG"}'::jsonb, '{"category":"ramp","effect":"creature","subtype":"mana_dork"}'::jsonb, 'curated', 0.96, 'verified', 'auto', 'PG254: promoted focused runtime rule for Faeburrow Elder; source is local XMage-backed ManaLoom runtime/test batch for blink, static restriction, or legacy exact waiver.', 'deprecate_nonmatching_rows'),
    ('neoform', 'Neoform', 'ae81715abd94b17c07451a09cf5b8db6', 'battle_rule_v1:1a244213e27ba84cc802817d801fdfbd', '{"battle_model_scope":"sacrifice_creature_tutor_creature_mv_plus_one_to_battlefield_counter_v1","destination":"battlefield","effect":"tutor","enters_with_plus_one_counter":true,"requires_sacrifice_creature":true,"sacrificed_creature_mv_plus_one":true,"target_type":"creature"}'::jsonb, '{"category":"tutor","effect":"tutor"}'::jsonb, 'curated', 0.96, 'verified', 'auto', 'PG254: promoted focused runtime rule for Neoform; source is local XMage-backed ManaLoom runtime/test batch for blink, static restriction, or legacy exact waiver.', 'deprecate_nonmatching_rows'),
    ('ephemerate', 'Ephemerate', '4671452857f7b532c0c9cc6088b3e25c', 'battle_rule_v1:8e1b9773684b97c3d24b091de88a5517', '{"battle_model_scope":"exile_then_return_target_creature_you_control_rebound_v1","blink_target_scope":"creature_you_control","destination":"battlefield","effect":"blink","instant":true,"rebound":true,"return_timing":"immediate_or_same_resolution","target":"creature_you_control","zone_transition":"exile_then_return"}'::jsonb, '{"category":"unknown","effect":"blink","target":"creature_you_control","timing":"instant"}'::jsonb, 'curated', 0.96, 'verified', 'auto', 'PG254: promoted focused runtime rule for Ephemerate; source is local XMage-backed ManaLoom runtime/test batch for blink, static restriction, or legacy exact waiver.', 'deprecate_nonmatching_rows'),
    ('displacer kitten', 'Displacer Kitten', '16da6e6f7355a5732ee2f80d55f35ebc', 'battle_rule_v1:0bb2c233457a8f1bb2420ff43b813d05', '{"ability_kind":"triggered","battle_model_scope":"noncreature_spell_cast_blink_up_to_one_nonland_permanent_you_control_v1","blink_optional":true,"blink_target_scope":"up_to_one_nonland_permanent_you_control","cmc":4.0,"colors":["U"],"destination":"battlefield","effect":"creature","mana_cost":"{3}{U}","power":2,"return_timing":"immediate_or_same_resolution","subtypes":["Cat","Beast"],"toughness":2,"trigger":"noncreature_spell_cast","trigger_effect":"blink","type_line":"Creature - Cat Beast","zone_transition":"exile_then_return"}'::jsonb, '{"category":"unknown","effect":"creature"}'::jsonb, 'curated', 0.96, 'verified', 'auto', 'PG254: promoted focused runtime rule for Displacer Kitten; source is local XMage-backed ManaLoom runtime/test batch for blink, static restriction, or legacy exact waiver.', 'deprecate_nonmatching_rows'),
    ('emiel the blessed', 'Emiel the Blessed', '9c568dbb78c72979a6e2e528f2ea5385', 'battle_rule_v1:c060974bde14bba7412e05ae3fae7c9d', '{"ability_kind":"activated_and_triggered","activated_blink":true,"activation_cost_generic":3,"battle_model_scope":"activated_blink_another_creature_you_control_plus_creature_etb_counter_metadata_v1","blink_target_scope":"another_creature_you_control","cmc":4.0,"colors":["W"],"controlled_other_creature_etb_counter_cost":"{G/W}","controlled_other_creature_etb_counter_count":1,"controlled_other_creature_etb_optional_counter":true,"controlled_unicorn_etb_counter_count":2,"destination":"battlefield","effect":"creature","legendary":true,"mana_cost":"{2}{W}{W}","power":4,"return_timing":"immediate_or_same_resolution","subtypes":["Unicorn"],"toughness":4,"type_line":"Legendary Creature - Unicorn","zone_transition":"exile_then_return"}'::jsonb, '{"category":"unknown","effect":"creature"}'::jsonb, 'curated', 0.96, 'verified', 'auto', 'PG254: promoted focused runtime rule for Emiel the Blessed; source is local XMage-backed ManaLoom runtime/test batch for blink, static restriction, or legacy exact waiver.', 'deprecate_nonmatching_rows'),
    ('deafening silence', 'Deafening Silence', '7ee68f02b4a79a4c3e00fbe14caceda1', 'battle_rule_v1:3acd8f1cd0385cea4d18af84cb76b7bf', '{"ability_kind":"static","battle_model_scope":"each_player_one_noncreature_spell_per_turn_static_v1","cmc":1.0,"colors":["W"],"effect":"passive","mana_cost":"{W}","restricted_spell_scope":"noncreature_spells","restriction_controller_scope":"each_player","spell_limit_per_turn":1,"static_rule_restriction":true,"type_line":"Enchantment"}'::jsonb, '{"category":"unknown","effect":"passive"}'::jsonb, 'curated', 0.96, 'verified', 'auto', 'PG254: promoted focused runtime rule for Deafening Silence; source is local XMage-backed ManaLoom runtime/test batch for blink, static restriction, or legacy exact waiver.', 'deprecate_nonmatching_rows'),
    ('archon of emeria', 'Archon of Emeria', 'a52d85813ecf212a3bfc84e249a2c90a', 'battle_rule_v1:160715b74767da0ffe53d66b25a44936', '{"ability_kind":"static","battle_model_scope":"each_player_one_spell_per_turn_opponent_nonbasic_lands_enter_tapped_v1","cmc":3.0,"colors":["W"],"effect":"creature","flying":true,"mana_cost":"{2}{W}","opponents_nonbasic_lands_enter_tapped":true,"power":2,"restricted_spell_scope":"spells","restriction_controller_scope":"each_player","spell_limit_per_turn":1,"static_rule_restriction":true,"subtypes":["Archon"],"toughness":3,"type_line":"Creature - Archon"}'::jsonb, '{"category":"unknown","effect":"creature"}'::jsonb, 'curated', 0.96, 'verified', 'auto', 'PG254: promoted focused runtime rule for Archon of Emeria; source is local XMage-backed ManaLoom runtime/test batch for blink, static restriction, or legacy exact waiver.', 'deprecate_nonmatching_rows'),
    ('eidolon of rhetoric', 'Eidolon of Rhetoric', 'cf8c850002241fd1afe4e8ca46884774', 'battle_rule_v1:137c1bd9ef3c7095ba82cef057c36d20', '{"ability_kind":"static","battle_model_scope":"each_player_one_spell_per_turn_static_creature_v1","cmc":3.0,"colors":["W"],"effect":"creature","mana_cost":"{2}{W}","power":1,"restricted_spell_scope":"spells","restriction_controller_scope":"each_player","spell_limit_per_turn":1,"static_rule_restriction":true,"subtypes":["Spirit"],"toughness":4,"type_line":"Enchantment Creature - Spirit"}'::jsonb, '{"category":"unknown","effect":"creature"}'::jsonb, 'curated', 0.96, 'verified', 'auto', 'PG254: promoted focused runtime rule for Eidolon of Rhetoric; source is local XMage-backed ManaLoom runtime/test batch for blink, static restriction, or legacy exact waiver.', 'deprecate_nonmatching_rows'),
    ('ethersworn canonist', 'Ethersworn Canonist', 'e8466942a00d320a7a9c067c0861fb27', 'battle_rule_v1:34c3e895d3a7ef2fdb960e8de4403308', '{"ability_kind":"static","artifact":true,"battle_model_scope":"each_player_one_nonartifact_spell_per_turn_static_artifact_creature_v1","cmc":2.0,"colors":["W"],"effect":"creature","mana_cost":"{1}{W}","power":2,"restricted_spell_scope":"nonartifact_spells","restriction_controller_scope":"each_player","spell_limit_per_turn":1,"static_rule_restriction":true,"subtypes":["Human","Cleric"],"toughness":2,"type_line":"Artifact Creature - Human Cleric"}'::jsonb, '{"category":"unknown","effect":"creature"}'::jsonb, 'curated', 0.96, 'verified', 'auto', 'PG254: promoted focused runtime rule for Ethersworn Canonist; source is local XMage-backed ManaLoom runtime/test batch for blink, static restriction, or legacy exact waiver.', 'deprecate_nonmatching_rows')
), deprecated AS (
  UPDATE public.card_battle_rules r
  SET review_status = 'deprecated', execution_status = 'disabled', updated_at = now(),
      notes = concat_ws(E'\n', nullif(r.notes, ''), 'PG254: disabled stale shadow before curated tested exact runtime promotion.')
  FROM proposed p
  WHERE r.normalized_name = p.normalized_name
    AND p.shadow_handling = 'deprecate_nonmatching_rows'
    AND r.logical_rule_key <> p.logical_rule_key
    AND (r.review_status <> 'deprecated' OR r.execution_status <> 'disabled')
  RETURNING r.*
), target_cards AS (
  SELECT DISTINCT ON (p.normalized_name) p.normalized_name, c.id, c.name
  FROM proposed p
  JOIN public.cards c
    ON (lower(c.name) = p.normalized_name OR split_part(lower(c.name), ' // ', 1) = p.normalized_name)
   AND md5(coalesce(c.oracle_text, '')) = p.oracle_hash
  ORDER BY p.normalized_name, c.name
), upserted AS (
  INSERT INTO public.card_battle_rules (normalized_name, logical_rule_key, card_id, card_name, effect_json, deck_role_json, source, confidence, review_status, execution_status, rule_version, oracle_hash, notes, reviewed_by, reviewed_at, created_at, updated_at, last_seen_at)
  SELECT p.normalized_name, p.logical_rule_key, tc.id, tc.name, p.effect_json, p.deck_role_json, p.source, p.confidence, p.review_status, p.execution_status, 1, p.oracle_hash, p.notes, 'codex-pg254', now(), now(), now(), now()
  FROM proposed p
  JOIN target_cards tc ON tc.normalized_name = p.normalized_name
  ON CONFLICT (normalized_name, logical_rule_key) DO UPDATE
  SET card_id=EXCLUDED.card_id, card_name=EXCLUDED.card_name, effect_json=EXCLUDED.effect_json, deck_role_json=EXCLUDED.deck_role_json, source=EXCLUDED.source, confidence=EXCLUDED.confidence, review_status=EXCLUDED.review_status, execution_status=EXCLUDED.execution_status, rule_version=EXCLUDED.rule_version, oracle_hash=EXCLUDED.oracle_hash, notes=EXCLUDED.notes, reviewed_by=EXCLUDED.reviewed_by, reviewed_at=EXCLUDED.reviewed_at, updated_at=now(), last_seen_at=now()
  RETURNING *
)
SELECT (SELECT count(*) FROM deprecated) AS deprecated_rows, (SELECT count(*) FROM upserted) AS upserted_rows;

COMMIT;
